348→export function archiveItems(queueName: string, items: QueueItem[]): void {
349→  if (items.length === 0) return;
350→  ensureDir(ARCHIVE_DIR);
351→  const archivePath = join(ARCHIVE_DIR, `${queueName}-archive.jsonl`);
352→  const content = items.map((item) => JSON.stringify(item)).join("\n") + "\n";
