366→function loadRoutingConfig(): RoutingConfig {
367→  if (!existsSync(ROUTING_RULES_FILE)) {
368→    return {
369→      version: 1,
370→      routes: [{ pattern: "*", queue: "approvals", priority: 2, requiresApproval: true }],
371→      defaults: { priority: 2, expiryDays: 30 },
372→    };
373→  }
374→
375→  const content = readFileSync(ROUTING_RULES_FILE, "utf-8");
376→  return parseYaml(content) as RoutingConfig;
377→}
